export const any = <T = any, O extends Partial<Omit<AnySchema<T>, "type" | "__tsType">> = {}>(
	opts: O = {} as O,
): AnySchema<T> & O =>
	({
		type: "any",
		...opts,
	}) as AnySchema<T> & O;

/**
 * Literal schema - constant value used for discriminators in unions.
 * The value is not intended to be editable and consumes no serialized bytes.
 */
export const literal = <V extends string | number | boolean, O extends Partial<CommonSchema> = {}>(
	value: V,
	opts: O = {} as O,
) => {
	return {
		type: "literal",
		value,
		...opts,
	} as const;
};

/**
 * Union schema - discriminated union of object variants.
 * key - name of the discriminator field
 * variants - array of object schemas where each variant must include a literal field for the key
 */
export const union = <K extends string, V extends (ObjectSchema & { fields: { [k in K]: LiteralSchema } })[]>(
	key: K,
	variants: [...V],
): { type: "union"; key: K; variants: [...V] } => ({
	type: "union",
	key,
	variants,
});

export function list<T extends Schema>(of: T): { type: "list"; of: T };
export function list<T extends Schema, O extends Partial<Omit<ListSchema, "type" | "of">>>(
	of: T,
	opts: O,
): { type: "list"; of: T } & O;
export function list<T extends Schema, O extends Partial<Omit<ListSchema, "type" | "of">> = {}>(
	of: T,
	opts?: O,
): { type: "list"; of: T } | ({ type: "list"; of: T } & O) {
	return {
		type: "list",
		of,
		...(opts as O | undefined),
	} as unknown as any;
}

export function object<F extends Record<string, Schema>>(fields: F): { type: "object"; fields: F };
export function object<
	F extends Record<string, Schema>,
	O extends Partial<Omit<ObjectSchema, "type" | "fields">>,
>(fields: F, opts: O): { type: "object"; fields: F } & O;
export function object<
	F extends Record<string, Schema>,
	O extends Partial<Omit<ObjectSchema, "type" | "fields">> = {},
>(fields: F, opts?: O): { type: "object"; fields: F } | ({ type: "object"; fields: F } & O) {
	return {
		type: "object",
		fields,
		...(opts as O | undefined),
	} as unknown as any;
}

export function record<F extends Record<string, Schema>>(fields: F): { type: "record"; field: F };
export function record<F extends Schema, O extends Partial<Omit<RecordSchema, "type" | "field">>>(
	field: F,
	opts: O,
): { type: "record"; field: F } & O;
export function record<F extends Schema, O extends Partial<Omit<RecordSchema, "type" | "field">> = {}>(
	field: F,
	opts?: O,
): { type: "record"; field: F } | ({ type: "record"; field: F } & O) {
	return {
		type: "record",
		field,
		...(opts as O | undefined),
	} as unknown as any;
}
